SELECT pr.id, pr.user_id AS userId, pr.penalty_type AS penaltyType, pr.reason, pr.operator_id AS operatorId, pr.penalty_time AS penaltyTime, pr.expire_time AS expireTime, pr.status, pr.remark, pr.created_at AS createdAt, u.username AS username, ou.username AS operatorName FROM penalty_records pr LEFT JOIN users u ON pr.user_id = u.id LEFT JOIN admin_users ou ON pr.operator_id = ou.id
AND pr.user_id = #{userId} AND pr.penalty_type = #{penaltyType} AND pr.status = #{status}
ORDER BY pr.created_at DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM penalty_records pr

    AND pr.user_id = #{userId}
    AND pr.penalty_type = #{penaltyType}
    AND pr.status = #{status}
